/* global React */

// Polilabs — Landing page. Public-facing surface: the marketing thesis
// (anti-hallucination), an ambient knowledge-graph visualization built
// from the live Kùzu corpus, a "by the numbers" band of cited stats,
// and a brief "how it works" triptych.
//
// Every statistic on this page is anchored to a numbered footnote at the
// bottom. The graph is data from web-design-a/landing-graph.json, which
// is regenerated by scripts/build_landing_graph.py — no synthetic edges.

const { useState, useEffect, useRef } = React;

// ── LandingGraph ────────────────────────────────────────────────────────
// Canvas-rendered force-relaxed graph that drifts gently after settling.
// We run ~220 iterations of damped springs on mount to find equilibrium
// positions, then switch to an ambient mode: each node oscillates in a
// small Lissajous orbit around its relaxed position. The drift is small
// enough to read as "alive," not "busy." Hover highlights the node and
// its direct neighborhood.
function LandingGraph({ data, height = 480 }) {
  const wrapRef = useRef(null);
  const canvasRef = useRef(null);
  const [hover, setHover] = useState(null); // { node, x, y } in CSS px
  const [width, setWidth] = useState(720);

  // Width-track the parent. Height is fixed so the layout settles once.
  useEffect(() => {
    if (!wrapRef.current) return;
    const ro = new ResizeObserver((entries) => {
      for (const e of entries) {
        const w = Math.max(280, Math.round(e.contentRect.width));
        setWidth(w);
      }
    });
    ro.observe(wrapRef.current);
    return () => ro.disconnect();
  }, []);

  useEffect(() => {
    if (!data || !canvasRef.current) return;
    const W = width, H = height;
    const cvs = canvasRef.current;
    const dpr = window.devicePixelRatio || 1;
    cvs.width = W * dpr;
    cvs.height = H * dpr;
    cvs.style.width = W + "px";
    cvs.style.height = H + "px";
    const ctx = cvs.getContext("2d");
    ctx.scale(dpr, dpr);

    // ── build mutable node + edge tables ─────────────────────────────
    const rng = (() => {
      // Deterministic seed so the layout looks the same across reloads
      // (no jarring "different graph every time" feeling).
      let s = 1337;
      return () => {
        s = (s * 16807) % 2147483647;
        return s / 2147483647;
      };
    })();

    const nodes = data.nodes.map((n) => ({
      ...n,
      // initial scatter — seeded so consecutive page loads relax to a
      // visually similar layout.
      x: W / 2 + (rng() - 0.5) * W * 0.55,
      y: H / 2 + (rng() - 0.5) * H * 0.55,
      vx: 0,
      vy: 0,
      r: 2.5 + Math.sqrt(Math.max(1, n.degree)) * 0.85,
      phase: rng() * Math.PI * 2,
      ampX: 2.5 + rng() * 4.5,
      ampY: 2.5 + rng() * 4.5,
      freq: 0.00035 + rng() * 0.00045,
    }));
    const id2i = {};
    nodes.forEach((n, i) => { id2i[n.id] = i; });

    const edges = data.edges
      .filter((e) => id2i[e.a] !== undefined && id2i[e.b] !== undefined)
      .map((e) => ({
        a: id2i[e.a],
        b: id2i[e.b],
        w: e.w,
        terms: e.terms || [],
      }));

    const adjacency = new Map();
    edges.forEach((e) => {
      if (!adjacency.has(e.a)) adjacency.set(e.a, new Set());
      if (!adjacency.has(e.b)) adjacency.set(e.b, new Set());
      adjacency.get(e.a).add(e.b);
      adjacency.get(e.b).add(e.a);
    });

    // ── one-shot relaxation: damped springs + repulsion + gravity ────
    // Iteration count and constants tuned by eye for n ≈ 55. Cheap
    // (O(n²) inner loop is ~3000 ops per iter).
    const relax = (iters) => {
      for (let it = 0; it < iters; it++) {
        const tEase = 1 - it / iters; // cool over time
        for (let i = 0; i < nodes.length; i++) {
          for (let j = i + 1; j < nodes.length; j++) {
            const A = nodes[i], B = nodes[j];
            let dx = B.x - A.x, dy = B.y - A.y;
            let d2 = dx * dx + dy * dy;
            if (d2 < 1) { dx = 0.5; dy = 0.5; d2 = 0.5; }
            const inv = 1 / Math.sqrt(d2);
            const f = 1200 / d2; // repulsion
            const fx = dx * inv * f, fy = dy * inv * f;
            A.vx -= fx; A.vy -= fy;
            B.vx += fx; B.vy += fy;
          }
        }
        for (const e of edges) {
          const A = nodes[e.a], B = nodes[e.b];
          const dx = B.x - A.x, dy = B.y - A.y;
          const d = Math.sqrt(dx * dx + dy * dy) || 1;
          const target = 70 + 6 / Math.sqrt(e.w); // heavier edges sit slightly closer
          const f = (d - target) * 0.06 * (1 + Math.log(e.w));
          const fx = (dx / d) * f, fy = (dy / d) * f;
          A.vx += fx; A.vy += fy;
          B.vx -= fx; B.vy -= fy;
        }
        const cx = W / 2, cy = H / 2;
        for (const n of nodes) {
          n.vx += (cx - n.x) * 0.006;
          n.vy += (cy - n.y) * 0.006;
          n.vx *= 0.82 + 0.06 * tEase; // damp
          n.vy *= 0.82 + 0.06 * tEase;
          n.x += n.vx;
          n.y += n.vy;
          const pad = 24;
          if (n.x < pad) n.x = pad;
          if (n.x > W - pad) n.x = W - pad;
          if (n.y < pad) n.y = pad;
          if (n.y > H - pad) n.y = H - pad;
        }
      }
    };
    relax(220);
    // Lock the relaxed positions as the orbit centers for ambient drift.
    for (const n of nodes) {
      n.cx = n.x;
      n.cy = n.y;
    }

    // ── interaction state lives in refs (not state) to keep the RAF
    //    loop allocation-free and avoid re-running this whole effect.
    let hoverIdx = null;
    let mouseLost = true;

    const setHoverNode = (i) => {
      hoverIdx = i;
      if (i == null) setHover(null);
      else {
        const n = nodes[i];
        setHover({
          node: n,
          // these are CSS pixels relative to the canvas wrapper
          x: n.x,
          y: n.y,
        });
      }
    };

    const onMove = (ev) => {
      const rect = cvs.getBoundingClientRect();
      const mx = ev.clientX - rect.left;
      const my = ev.clientY - rect.top;
      mouseLost = false;
      let best = null, bestD = 16 * 16;
      for (let i = 0; i < nodes.length; i++) {
        const n = nodes[i];
        const dx = mx - n.x, dy = my - n.y;
        const d2 = dx * dx + dy * dy;
        if (d2 < bestD) { bestD = d2; best = i; }
      }
      if (best !== hoverIdx) setHoverNode(best);
    };
    const onLeave = () => {
      mouseLost = true;
      if (hoverIdx !== null) setHoverNode(null);
    };
    cvs.addEventListener("mousemove", onMove);
    cvs.addEventListener("mouseleave", onLeave);

    // ── render loop ──────────────────────────────────────────────────
    let raf = 0;
    const draw = (t) => {
      ctx.clearRect(0, 0, W, H);

      // ambient drift
      for (const n of nodes) {
        n.x = n.cx + Math.cos(t * n.freq + n.phase) * n.ampX;
        n.y = n.cy + Math.sin(t * n.freq * 1.3 + n.phase * 0.7) * n.ampY;
      }

      const adj = hoverIdx != null ? (adjacency.get(hoverIdx) || new Set()) : null;

      // edges first so nodes paint over them
      for (const e of edges) {
        const A = nodes[e.a], B = nodes[e.b];
        const isHL = adj && (e.a === hoverIdx || e.b === hoverIdx);
        if (isHL) {
          ctx.strokeStyle = "rgba(30, 63, 168, 0.55)";
          ctx.lineWidth = 1.4;
        } else {
          const a = 0.07 + Math.min(0.12, e.w * 0.012);
          ctx.strokeStyle = `rgba(76, 66, 50, ${a})`;
          ctx.lineWidth = 0.7 + Math.min(0.7, e.w * 0.06);
        }
        ctx.beginPath();
        ctx.moveTo(A.x, A.y);
        ctx.lineTo(B.x, B.y);
        ctx.stroke();
      }

      for (let i = 0; i < nodes.length; i++) {
        const n = nodes[i];
        const isHover = hoverIdx === i;
        const isAdj = adj && adj.has(i);
        if (isHover) ctx.fillStyle = "#1e3fa8";
        else if (isAdj) ctx.fillStyle = "#3b5bd0";
        else ctx.fillStyle = "rgba(40, 36, 28, 0.7)";
        ctx.beginPath();
        ctx.arc(n.x, n.y, n.r + (isHover ? 1.5 : 0), 0, Math.PI * 2);
        ctx.fill();
        if (isHover) {
          ctx.strokeStyle = "rgba(30, 63, 168, 0.30)";
          ctx.lineWidth = 1;
          ctx.beginPath();
          ctx.arc(n.x, n.y, n.r + 6, 0, Math.PI * 2);
          ctx.stroke();
        }
      }

      // Refresh the tooltip position so it tracks the drifting node.
      if (hoverIdx !== null && !mouseLost) {
        const n = nodes[hoverIdx];
        setHover((h) => (h && h.node && h.node.id === n.id ? { ...h, x: n.x, y: n.y } : h));
      }

      raf = requestAnimationFrame(draw);
    };
    raf = requestAnimationFrame(draw);

    return () => {
      cancelAnimationFrame(raf);
      cvs.removeEventListener("mousemove", onMove);
      cvs.removeEventListener("mouseleave", onLeave);
    };
  }, [data, width, height]);

  return (
    <div ref={wrapRef} className="land-graph">
      <canvas ref={canvasRef} aria-hidden="true" />
      {hover && (
        <div
          className="land-graph-tip"
          style={{
            left: Math.min(width - 260, Math.max(8, hover.x + 14)),
            top: Math.min(height - 88, Math.max(8, hover.y + 14)),
          }}
        >
          <div className="tip-ref mono">
            {hover.node.ref} · {hover.node.congress}th
          </div>
          <div className="tip-title">{hover.node.label}</div>
          {hover.node.sponsor && (
            <div className="tip-sponsor mono">{hover.node.sponsor}</div>
          )}
        </div>
      )}
    </div>
  );
}

// ── Stat tile ────────────────────────────────────────────────────────────
// One headline number + a short body + a footnote anchor. The footnote
// is the contract: nothing here gets to make a number-shaped claim
// without a link back to a primary source.
function Stat({ n, unit, body, foot }) {
  return (
    <div className="land-stat">
      <div className="land-stat-n">
        {n}
        {unit ? <span className="land-stat-unit">{unit}</span> : null}
      </div>
      <div className="land-stat-body">
        {body}
        <sup>
          <a href={`#fn${foot}`} className="land-fn-link" aria-label={`footnote ${foot}`}>{foot}</a>
        </sup>
      </div>
    </div>
  );
}

function Pillar({ title, body }) {
  return (
    <div className="land-pillar">
      <div className="land-pillar-title">{title}</div>
      <p className="land-pillar-body">{body}</p>
    </div>
  );
}

// ── Landing ──────────────────────────────────────────────────────────────
function Landing({ user, onOpenWorkspace, onSignIn, onSignOut }) {
  // The graph + corpus stats both come from the same JSON, generated by
  // scripts/build_landing_graph.py off the live Kùzu DB.
  const [graphData, setGraphData] = useState(null);
  const [corpus, setCorpus] = useState(null);
  const [loadError, setLoadError] = useState(false);

  useEffect(() => {
    let cancelled = false;
    fetch("landing-graph.json")
      .then((r) => {
        if (!r.ok) throw new Error(`HTTP ${r.status}`);
        return r.json();
      })
      .then((j) => {
        if (cancelled) return;
        setGraphData(j.graph);
        setCorpus(j.corpus);
      })
      .catch(() => { if (!cancelled) setLoadError(true); });
    return () => { cancelled = true; };
  }, []);

  // Fall back to known-good corpus counts if the JSON failed to load.
  // (We never invent numbers — these are the values committed in the
  // fixture, so they match what users see when the file does load.)
  const c = corpus || { bills: 191, sections: 29616, defined_terms: 1241, external_citations: 646 };

  return (
    <div className="land">
      <header className="land-header">
        <div className="land-brand">polilabs</div>
        <nav className="land-nav">
          {user ? (
            <React.Fragment>
              <span className="land-user mono">{user.email}</span>
              <button type="button" className="land-link" onClick={onSignOut}>
                Sign out
              </button>
            </React.Fragment>
          ) : (
            <button type="button" className="land-link" onClick={onSignIn}>
              Sign in
            </button>
          )}
        </nav>
      </header>

      <main className="land-main">
        {/* HERO */}
        <section className="land-hero">
          <div className="land-hero-copy">
            <div className="land-eyebrow mono">
              U.S. federal AI-governance · 118th–119th Congress
            </div>
            <h1 className="land-h1">
              Read the law,<br /> not a summary of it.
            </h1>
            <p className="land-lede">
              polilabs is a citation-accurate research instrument for U.S.
              federal AI-governance legislation. Every answer is grounded
              in verbatim bill text and mechanically-extracted structure —
              definitions, amendments, citations. If it is not in the
              bill, polilabs does not say it.
            </p>
            <div className="land-cta-row">
              <button type="button" className="land-cta" onClick={onOpenWorkspace}>
                Open the workspace <span aria-hidden="true">→</span>
              </button>
              <div className="land-corpus mono">
                <b>{c.bills}</b>&nbsp;bills
                <span className="land-dot">·</span>
                <b>118th–119th</b>&nbsp;Congress
              </div>
            </div>
          </div>
          <div className="land-hero-graph">
            {graphData ? (
              <LandingGraph data={graphData} height={480} />
            ) : (
              <div className="land-graph-placeholder">
                {loadError ? "graph data unavailable" : "loading corpus…"}
              </div>
            )}
            <div className="land-graph-caption mono">
              Each node is a bill. An edge connects two bills that share at
              least one defined term — built directly from the corpus,
              never synthesized.
            </div>
          </div>
        </section>

        {/* BY THE NUMBERS */}
        <section className="land-section land-stats-section">
          <div className="land-section-label mono">
            <span>By the numbers</span>
            <span className="land-section-tag mono">
              every figure linked to a primary source
            </span>
          </div>
          <div className="land-stats-grid">
            <Stat n="19,315" body="bills introduced in the 118th Congress; 3% became law." foot={1} />
            <Stat n="9×" body="denser legislation per enacted law than in 1955." foot={2} />
            <Stat n="34%" body="of legal queries hallucinated by Westlaw's AI-Assisted Research, despite vendor 'hallucination-free' claims." foot={3} />
            <Stat n="3.1 yrs" body="median Hill-staff tenure — roughly a third haven't served a full Congress." foot={4} />
            <Stat n="84%" body="of senior Hill staff: 'we can't accomplish as much as we'd like.'" foot={5} />
            <Stat n="$34 to $1" body="corporate vs. labor + public-interest lobbying ratio." foot={6} />
            <Stat n="150+" body="AI bills introduced in the 118th Congress; zero became law." foot={7} />
            <Stat n="½" body="House committee staff today versus 1980, as policy complexity has grown." foot={8} />
          </div>
        </section>

        {/* HOW IT WORKS */}
        <section className="land-section">
          <div className="land-section-label mono">
            <span>How it works</span>
          </div>
          <div className="land-pillars">
            <Pillar
              title="Mechanically extracted"
              body="Definitions, amendments, and citations are pulled from the bill XML directly. No model paraphrases the law before you read it."
            />
            <Pillar
              title="Verbatim text, synced"
              body="Click a citation; the matching span lights up in the bill text. If the substring can't be located, the highlight degrades to scroll — it never invents one."
            />
            <Pillar
              title="Honest unknowns"
              body="If the corpus does not contain an answer, polilabs says so. No paraphrase, no inference, no plausible-sounding completion."
            />
          </div>
        </section>

        {/* WHAT'S IN THE CORPUS */}
        <section className="land-section">
          <div className="land-section-label mono">
            <span>What's in the corpus</span>
            <span className="land-section-tag mono">v1 · 118th–119th Congress</span>
          </div>
          <div className="land-corpus-grid">
            <div className="land-corpus-cell">
              <b>{c.bills.toLocaleString()}</b>
              <span>bills</span>
            </div>
            <div className="land-corpus-cell">
              <b>{c.sections.toLocaleString()}</b>
              <span>sections</span>
            </div>
            <div className="land-corpus-cell">
              <b>{c.defined_terms.toLocaleString()}</b>
              <span>defined terms</span>
            </div>
            <div className="land-corpus-cell">
              <b>{c.external_citations.toLocaleString()}</b>
              <span>external citations</span>
            </div>
          </div>
        </section>

        {/* CTA REPRISE */}
        <section className="land-cta-band">
          <div className="land-cta-band-copy">
            <div className="land-cta-band-h">Open the corpus.</div>
            <div className="land-cta-band-sub">
              Ask a question. Read what the bill actually says.
            </div>
          </div>
          <button type="button" className="land-cta" onClick={onOpenWorkspace}>
            Open the workspace <span aria-hidden="true">→</span>
          </button>
        </section>

        {/* FOOTNOTES */}
        <section className="land-section land-notes-section">
          <div className="land-section-label mono">
            <span>Sources</span>
            <span className="land-section-tag mono">primary citations, all linked</span>
          </div>
          <ol className="land-notes">
            <li id="fn1">
              GovTrack.us, <em>Statistics and Historical Comparison</em> (accessed 2026). <a href="https://www.govtrack.us/congress/bills/statistics" target="_blank" rel="noopener noreferrer">govtrack.us/congress/bills/statistics</a>. The 118th Congress saw 19,315 measures introduced and 614 (3%) enacted, including via incorporation into other bills.
            </li>
            <li id="fn2">
              Pew Research Center (2021), reporting Brookings Institution <em>Vital Statistics on Congress</em> data. <a href="https://www.pewresearch.org/short-reads/2021/01/21/nothing-lame-about-this-lame-duck-116th-congress-had-busiest-post-election-session-in-recent-history/" target="_blank" rel="noopener noreferrer">pewresearch.org</a>. The 84th Congress (1955–56) enacted ~1,000 public laws averaging under 2 pages each; the 115th (2017–18) enacted 442 laws averaging nearly 18 pages.
            </li>
            <li id="fn3">
              Magesh, Surani, Dahl, Suzgun, Manning, Ho. <em>Hallucination-Free? Assessing the Reliability of Leading AI Legal Research Tools.</em> Journal of Empirical Legal Studies (2024). <a href="https://dho.stanford.edu/wp-content/uploads/Legal_RAG_Hallucinations.pdf" target="_blank" rel="noopener noreferrer">Stanford RegLab preprint</a>. Westlaw AI-Assisted Research hallucinated on &gt;34% of benchmark queries; Lexis+ AI and Ask Practical Law on &gt;17%.
            </li>
            <li id="fn4">
              New America / Congressional Capacity Survey, <em>Congressional Staffers' Job Satisfaction, Career Trajectories, and Compensation</em> (2021, 2019 underlying data). <a href="https://www.newamerica.org/insights/congressional-brain-drain/congressional-staffers-job-satisfaction-career-trajectories-and-compensation/" target="_blank" rel="noopener noreferrer">newamerica.org</a>. Mean tenure 3.1 years (SD 1.9); roughly one-third of legislative staffers have not yet served a full Congress.
            </li>
            <li id="fn5">
              Congressional Management Foundation, <em>State of the Congress 2024</em>. <a href="https://www.congressfoundation.org/s/cmf-state-of-the-congress-2024.pdf" target="_blank" rel="noopener noreferrer">congressfoundation.org</a>. n = 138 senior Hill staff, 5% response rate; CMF flags that results "are only truly representative of survey respondents."
            </li>
            <li id="fn6">
              Lee Drutman, <em>The Business of America is Lobbying</em> (Oxford University Press, 2015), summarized at New America. <a href="https://www.newamerica.org/insights/there-wasnt-always-much-corporate-lobbying/" target="_blank" rel="noopener noreferrer">newamerica.org</a>. Figures are circa 2015 and rely on reported lobbying, widely viewed as an undercount.
            </li>
            <li id="fn7">
              Brennan Center for Justice, <em>Artificial Intelligence Legislation Tracker</em> (updated 2025). <a href="https://www.brennancenter.org/our-work/research-reports/artificial-intelligence-legislation-tracker" target="_blank" rel="noopener noreferrer">brennancenter.org</a>. 150+ AI bills introduced in the 118th Congress; none became law.
            </li>
            <li id="fn8">
              R Street Institute / Lee Drutman et al., <em>Congress must invest in its own capacity again</em> (coalition letter, 2015), drawing on CRS reports. <a href="https://www.rstreet.org/commentary/congress-must-invest-in-its-own-capacity-again/" target="_blank" rel="noopener noreferrer">rstreet.org</a>. House committee staff have fallen to roughly half their 1980 levels.
            </li>
          </ol>
          <div className="land-meta mono">
            polilabs · {c.bills} bills · 118th–119th Congress · citation-accurate, no hallucination
          </div>
        </section>
      </main>
    </div>
  );
}

window.Landing = Landing;
